data {
  int<lower=0> N;                       // number of observations (groups)
  array[N] int<lower=0> y;              // successes
  array[N] int<lower=0> n;              // trials
}
parameters {
  real<lower=0> alpha;                  // Beta shape parameter
  real<lower=0> beta;                   // Beta shape parameter
  vector<lower=0, upper=1>[N] theta;    // group success probabilities
}
model {
  // Prior: p(alpha, beta) proportional to (alpha + beta)^(-5/2)
  target += -2.5 * log(alpha + beta);

  // Hierarchical structure
  theta ~ beta(alpha, beta);
  y ~ binomial(n, theta);
}

